onFilesSelected:
(async () => {
    const files = FilePicker_Scrap.files;
    if (!files || files.length === 0) return;

    const excelData = files[0].data;
    if (!excelData || excelData.length === 0) {
        showAlert("❌ File trống!", "error");
        return;
    }

    try {
        showAlert("⏳ Đang đẩy dữ liệu báo phế lên Database...", "info");
        let count = 0;

        for (let row of excelData) {
            // Lấy trực tiếp từ cột tool_code (Do file của bạn đã quá chuẩn rồi)
            if (!row.tool_code) continue; 

            await Action_AddScrap.run({
                stt: row.stt || null,
                workshop: row.workshop || '',
                tool_code: String(row.tool_code).trim(),
                tool_name: row.tool_name || '',
                unit: row.unit || '',
                quantity: Number(row.quantity) || 0,
                requester: row.requester || '',
                image_url: row.image_url || '',
                material_type: row.material_type || '',
                usage_location: row.usage_location || '',
                scrap_reason: row.scrap_reason || '',
                approver: row.approve || '' // Lấy đúng tên cột "approve" trong file của bạn
            });
            count++;
        }

        if (count > 0) {
            showAlert(`✅ Đã nhập thành công ${count} thiết bị báo phế!`, "success");
            await Get_Scrap_List.run(); // Load lại bảng hiển thị
        } else {
            showAlert("⚠️ Không có dòng dữ liệu hợp lệ (Cột tool_code bị trống)!", "warning");
        }

        resetWidget('FilePicker_Scrap', true);

    } catch (err) {
        showAlert("❌ Lỗi xử lý: " + err.message, "error");
    }
})();
